function stripHtml(html) {
  if (!html) return '';
  return html
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/\s+/g, ' ')
    .trim();
}

const items = $input.all();
const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);

const recentItems = items.filter(item => {
  const rawDate = item.json.pubDate || item.json.isoDate || item.json.date;
  if (!rawDate) return true;
  const pubDate = new Date(rawDate);
  return !isNaN(pubDate.getTime()) && pubDate >= cutoff;
});

return recentItems.slice(0, 10).map(item => {
  const rawContent = item.json.content || item.json.summary || item.json.description || item.json.contentSnippet || '';
  const cleanText = stripHtml(rawContent);

  return {
    json: {
      title:   item.json.title || 'Untitled',
      content: cleanText,
      text:    `TITLE: ${item.json.title}\nSOURCE: ${item.json.creator || item.json.author || 'Unknown'}\n\nCONTENT:\n${cleanText}`,
      link:    item.json.link || item.json.url || '',
      pubDate: item.json.pubDate || item.json.isoDate || new Date().toISOString(),
      source:  item.json.creator || item.json.author || 'Unknown'
    }
  };
});

const items = $input.all();

const today = new Date();
const mm   = String(today.getMonth() + 1).padStart(2, '0');
const dd   = String(today.getDate()).padStart(2, '0');
const yyyy = today.getFullYear();
const dateStr = `${mm}/${dd}/${yyyy}`;

const categoryMap = {
  'Ransomware':       ['ransomware', 'ransom'],
  'Malware':          ['malware', 'trojan', 'virus', 'worm', 'spyware', 'rootkit', 'backdoor'],
  'Phishing':         ['phishing', 'spear phishing', 'social engineering'],
  'Vulnerability':    ['vulnerability', 'cve', 'zero-day', 'zero day', 'patch', 'exploit'],
  'Data Breach':      ['data breach', 'data leak', 'leaked', 'exposed data', 'stolen data'],
  'Nation-State':     ['nation-state', 'apt', 'state-sponsored', 'china', 'russia', 'north korea', 'iran'],
  'AI Security':      ['artificial intelligence', 'machine learning', 'llm', 'deepfake', 'ai model'],
  'Cloud Security':   ['cloud', 'aws', 'azure', 'google cloud', 's3', 'kubernetes'],
  'Network Security': ['firewall', 'ddos', 'botnet', 'dns', 'vpn'],
  'Endpoint':         ['endpoint', 'windows', 'linux', 'macos', 'android', 'ios'],
};

// Parse each article from AI output
const articles = items.map(item => {
  let rawOutput = '';
  try {
    rawOutput = item.json.output[0].content[0].text || '';
  } catch (e) {
    rawOutput = item.json.text || item.json.content || '';
  }

  let title      = '';
  let summary    = '';
  let hook       = '';
  let importance = 5;

  try {
    const parsed = JSON.parse(rawOutput);
    title      = parsed.title      || item.json.title || 'Untitled';
    summary    = parsed.summary    || rawOutput;
    hook       = parsed.hook       || '';
    importance = Number(parsed.importance) || 5;
  } catch (e) {
    title   = item.json.title || 'Untitled';
    summary = rawOutput;
  }

  return { title, summary, hook, importance };
});

// Main text: all articles stacked
const mainText = articles
  .map(a => `${a.title}\n\n${a.summary}`)
  .join('\n\n---\n\n');

// CEO paragraph: top 3 by importance, fallback to first sentence
const topStories = [...articles]
  .sort((a, b) => b.importance - a.importance)
  .slice(0, 3);

const topHooks = topStories.map(a => {
  if (a.hook && a.hook.length > 5) return a.hook;
  const firstSentence = a.summary.split('.')[0];
  return firstSentence ? firstSentence.trim() + '.' : '';
}).filter(Boolean);

const ceoText = topHooks.join(' ');

// Categories across all articles
const allText = articles.map(a => a.summary).join(' ').toLowerCase();
const categories = [];

for (const [category, keywords] of Object.entries(categoryMap)) {
  if (keywords.some(kw => allText.includes(kw))) {
    categories.push(category);
  }
}

if (categories.length === 0) categories.push('General Security');

return [{
  json: {
    notionTitle: `${dateStr} CyberFeed`,
    mainText,
    ceoText,
    multiSelect:  categories,
    date:         new Date().toISOString().split('T')[0],
    status:       'Draft',
    articles:     articles.map(a => ({
      title:   a.title,
      summary: a.summary,
    })),
  }
}];

const pageId   = $input.first().json.id;
const articles = $('Tag Categories').first().json.articles;

if (!pageId)                       throw new Error('Page ID bulunamadı');
if (!articles || !articles.length) throw new Error('Articles bulunamadı');

// Parse **bold** markers into Notion rich_text array
function parseRichText(text, maxLen = 1900) {
  if (!text) return [{ type: 'text', text: { content: '' } }];

  text = text.replace(/\n/g, ' ').trim();
  if (text.length > maxLen) text = text.substring(0, maxLen);

  const richText = [];
  const boldRegex = /\*\*(.+?)\*\*/g;
  let lastIndex = 0;
  let match;

  while ((match = boldRegex.exec(text)) !== null) {
    if (match.index > lastIndex) {
      richText.push({
        type: 'text',
        text: { content: text.substring(lastIndex, match.index) },
        annotations: { bold: false, italic: false, strikethrough: false, underline: false, code: false, color: 'default' }
      });
    }
    richText.push({
      type: 'text',
      text: { content: match[1] },
      annotations: { bold: true, italic: false, strikethrough: false, underline: false, code: false, color: 'default' }
    });
    lastIndex = match.index + match[0].length;
  }

  if (lastIndex < text.length) {
    richText.push({
      type: 'text',
      text: { content: text.substring(lastIndex) },
      annotations: { bold: false, italic: false, strikethrough: false, underline: false, code: false, color: 'default' }
    });
  }

  return richText.length > 0 ? richText : [{ type: 'text', text: { content: text } }];
}

// Split summary into sentence-based chunks under 1900 chars
function chunkSummary(text) {
  if (!text) return [''];
  text = text.replace(/\n/g, ' ').trim();
  if (text.length <= 1900) return [text];

  const sentences = text.match(/[^.!?]+[.!?]+/g) || [text];
  const chunks = [];
  let current = '';

  sentences.forEach(sentence => {
    if ((current + sentence).length > 1900) {
      if (current) chunks.push(current.trim());
      current = sentence;
    } else {
      current += sentence;
    }
  });

  if (current.trim()) chunks.push(current.trim());
  return chunks;
}

const children = [];

articles.forEach((article, index) => {
  // Title as Heading 2
  children.push({
    object: 'block',
    type: 'heading_2',
    heading_2: {
      rich_text: parseRichText(article.title || 'Untitled')
    }
  });

  // Summary split into paragraphs with bold support
  const chunks = chunkSummary(article.summary || '');
  chunks.forEach(chunk => {
    children.push({
      object: 'block',
      type: 'paragraph',
      paragraph: {
        rich_text: parseRichText(chunk)
      }
    });
  });

  // Divider between articles
  if (index < articles.length - 1) {
    children.push({
      object: 'block',
      type: 'divider',
      divider: {}
    });
  }
});

return [{
  json: {
    pageId,
    body: JSON.stringify({ children })
  }
}];

